mapper.select:
select distinct elemntObject as elementObject, elemntchname as elementchname, elemntcode as elementCode, elemntrule as elementRule, moddate as modDate, author as author, iselemnt as isElement, sameid as sameId, createmode as createMode, l.code_value AS elementobjectType from synlte.ENTITY_ELEMENT r left join DSM_ALL_CODE_DATA l on r.elemntObject = l.code_value
(upper(r.elemntchname) like upper(concat('%',concat(#{searchText},'%'))))
and iselemnt in (
#{item}
)
and l.code_text = #{elementObject}
order by ${sort} ${sortOrder}
